using System.Reflection;
using System.Text;

string[] dlls = new[]
{
    "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/10.5.0/lib/net9.0/Microsoft.Extensions.AI.Abstractions.dll",
    "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.0/lib/net9.0/Microsoft.Extensions.AI.dll",
    "/home/runner/.nuget/packages/microsoft.agents.ai/1.3.0/lib/net9.0/Microsoft.Agents.AI.dll",
    "/home/runner/.nuget/packages/microsoft.extensions.ai.openai/10.3.0/lib/net9.0/Microsoft.Extensions.AI.OpenAI.dll",
    "/home/runner/.nuget/packages/openai/2.10.0/lib/net8.0/OpenAI.dll"
};

foreach (var path in dlls)
{
    if (!File.Exists(path))
    {
        Console.WriteLine($"\n{'='*70}");
        Console.WriteLine($"[MISSING] {Path.GetFileName(path)}");
        continue;
    }

    Console.WriteLine($"\n\n{'='*70}");
    Console.WriteLine($"FILE: {Path.GetFileName(path)}");
    Console.WriteLine($"{'='*70}");
    try
    {
        var asm = Assembly.LoadFrom(path);
        var types = asm.GetExportedTypes().OrderBy(t => t.FullName).ToList();

        Console.WriteLine($"Total Public Types: {types.Count}\n");

        foreach (var t in types)
        {
            Console.WriteLine($"\n[{t.FullName}]");

            // Show base class
            if (t.BaseType != null && t.BaseType != typeof(object) && !t.BaseType.Name.StartsWith("Nullable"))
                Console.WriteLine($"  BASE: {t.BaseType.Name}");

            // Show interfaces
            var interfaces = t.GetInterfaces().Where(i => i.IsPublic).ToList();
            if (interfaces.Any())
                Console.WriteLine($"  INTERFACES: {string.Join(", ", interfaces.Select(i => i.Name))}");

            // Show constructors
            var ctors = t.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
            if (ctors.Any())
            {
                foreach (var c in ctors)
                {
                    var cp = string.Join(", ", c.GetParameters().Select(p => 
                        $"{(p.ParameterType.IsGenericType ? p.ParameterType.Name.Split('`')[0] + "<>" : p.ParameterType.Name)} {p.Name}"));
                    Console.WriteLine($"  .ctor({cp})");
                }
            }

            // Show public methods (declared in this type)
            var methods = t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                .Where(m => !m.IsSpecialName)
                .OrderBy(m => m.Name)
                .ToList();

            foreach (var m in methods.Take(30))
            {
                var returnName = m.ReturnType.IsGenericType ? 
                    m.ReturnType.Name.Split('`')[0] + "<>" : m.ReturnType.Name;
                var parms = string.Join(", ", m.GetParameters().Select(p => 
                    $"{(p.ParameterType.IsGenericType ? p.ParameterType.Name.Split('`')[0] + "<>" : p.ParameterType.Name)} {p.Name}"));

                var isAsync = m.ReturnType.Name.Contains("Task");
                var prefix = isAsync ? "async " : "";
                Console.WriteLine($"  {prefix}{returnName} {m.Name}({parms})");
            }

            if (methods.Count > 30)
                Console.WriteLine($"  ... and {methods.Count - 30} more methods");

            // Show public properties
            var props = t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
                .OrderBy(p => p.Name)
                .ToList();

            foreach (var p in props)
            {
                var pname = p.PropertyType.IsGenericType ? 
                    p.PropertyType.Name.Split('`')[0] + "<>" : p.PropertyType.Name;
                var access = "";
                if (p.CanGet) access += "get";
                if (p.CanSet) access += access.Length > 0 ? ",set" : "set";
                Console.WriteLine($"  {pname} {p.Name} {{ {access} }}");
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"  ERROR: {ex.GetType().Name}: {ex.Message}");
    }
}
