public class MyAgent : AIAgent
{
    private readonly IChatClient _chatClient;
    private readonly string _systemPrompt = "You are a helpful assistant.";

    public MyAgent(IChatClient chatClient)
    {
        _chatClient = chatClient;
    }

    public override string Name => "MyAgent";
    public override string Id => "agent-v1";
    public override string Description => "A sample agent";

    public override async ValueTask<AgentSession> CreateSessionAsync(
        CancellationToken cancellationToken)
    {
        return new AgentSession();
    }

    public override async Task<AgentResponse> RunAsync(
        IEnumerable<ChatMessage> messages,
        AgentSession session,
        AgentRunOptions options,
        CancellationToken cancellationToken)
    {
        var history = new List<ChatMessage>
        {
            new(ChatRole.System, _systemPrompt)
        };
        history.AddRange(messages);

        var chatOptions = new ChatOptions();
        var response = await _chatClient.GetResponseAsync(history, chatOptions, cancellationToken);

        return new AgentResponse(new[] { response.Message }, response.FinishReason);
    }

    public override async IAsyncEnumerable<AgentResponseUpdate> RunStreamingAsync(
        IEnumerable<ChatMessage> messages,
        AgentSession session,
        AgentRunOptions options,
        [EnumeratorCancellation] CancellationToken cancellationToken)
    {
        var history = new List<ChatMessage>
        {
            new(ChatRole.System, _systemPrompt)
        };
        history.AddRange(messages);

        await foreach (var update in _chatClient.GetStreamingResponseAsync(
            history, new ChatOptions(), cancellationToken))
        {
            yield return new AgentResponseUpdate(
                new[] { new ChatMessage(ChatRole.Assistant, update.ContentUpdate) },
                update.FinishReason
            );
        }
    }

    // ... other required overrides
}


