{
    var response = await aiClient.GetResponseAsync("message", new ChatOptions());
    logger.LogInformation("Response received: {response}", response.Message.Text);
}
catch (OperationCanceledException)
{
    logger.LogWarning("Request cancelled");
}
catch (Exception ex)
{
    logger.LogError(ex, "Error in chat completion");
}

